[Fact]
public void FilesController_HasSinglePublicConstructor_TakingOnlyIFileService()
{
    // The ILogger<FilesController> dependency was dead code (assigned in
    // the constructor but never read), so the controller must expose exactly
    // one public constructor whose sole parameter is IFileService.
    var ctors = typeof(FilesController).GetConstructors();

    var ctor = Assert.Single(ctors);
    Assert.True(ctor!.IsPublic);

    var param = Assert.Single(ctor.GetParameters());
    Assert.Equal(typeof(IFileService), param.ParameterType);
    Assert.Equal("service", param.Name);
}

[Fact]
public void FilesController_DoesNotDeclareConstructor_TakingLogger()
{
    // The removed logger dependency must not be re-introduced as a second
    // constructor parameter under any arity.
    var twoArgCtor = typeof(FilesController).GetConstructor(new[]
    {
        typeof(IFileService),
        typeof(ILogger<FilesController>)
    });

    Assert.Null(twoArgCtor);
}

[Fact]
public void FilesController_DoesNotDeclareLoggerField()
{
    // The dead _logger field must be gone entirely: no private field named
    // _logger and no field whose type is an ILogger<...>.
    var fields = typeof(FilesController)
        .GetFields(BindingFlags.Public | BindingFlags.NonPublic |
                   BindingFlags.Static | BindingFlags.Instance);

    Assert.DoesNotContain(fields, f => f.Name == "_logger");
    Assert.DoesNotContain(fields, f =>
        f.FieldType.IsGenericType &&
        f.FieldType.GetGenericTypeDefinition() == typeof(ILogger<>));
}

